if (items.length === 0) {
  return [{ json: { hasItems: false, html: '<p>No posts found.</p>' } }];
}

const safe = s => (s || '').toString().replace(/</g,'&lt;').replace(/>/g,'&gt;');
const toLocal = ts => ts ? new Date(ts).toLocaleString() : '';

/** Totals **/
const totals = items.reduce((acc, i) => {
  const j = i.json;
  acc.posts += 1;
  acc.likes += Number(j.likes || 0);
  acc.replies += Number(j.replies || 0);
  acc.reposts += Number(j.reposts || 0);
  acc.quotes += Number(j.quotes || 0);
  acc.views += Number(j.views || 0);
  return acc;
}, {posts:0, likes:0, replies:0, reposts:0, quotes:0, views:0});

/** Table rows **/
const rows = items
  .sort((a,b) => new Date(b.json.timestamp) - new Date(a.json.timestamp))
  .map(i => {
    const j = i.json;
    return `
      <tr>
        <td>${toLocal(j.timestamp)}</td>
        <td style="max-width:520px;white-space:pre-wrap">${safe(j.text).slice(0,200)}${j.text?.length>200?'…':''}</td>
        <td style="text-align:right">${Number(j.likes||0)}</td>
        <td style="text-align:right">${Number(j.replies||0)}</td>
        <td style="text-align:right">${Number(j.reposts||0)}</td>
        <td style="text-align:right">${Number(j.quotes||0)}</td>
        <td style="text-align:right">${Number(j.views||0)}</td>
        <td><a href="${j.permalink}">Link</a></td>
      </tr>`;
  }).join('');

/** HTML **/
const html = `
  <div style="font-family:system-ui,-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif">
    <h2 style="margin:0 0 8px">Threads Analytics Report (${items.length} posts)</h2>
    <p style="margin:0 0 16px">
      👍 ${totals.likes}&nbsp;&nbsp;💬 ${totals.replies}&nbsp;&nbsp;🔁 ${totals.reposts}&nbsp;&nbsp;🗨️ ${totals.quotes}&nbsp;&nbsp;👁️ ${totals.views}
    </p>
    <table border="1" cellspacing="0" cellpadding="8" style="border-collapse:collapse;width:100%;font-size:14px">
      <thead style="background:#f6f7f9">
        <tr>
          <th style="text-align:left">Time</th>
          <th style="text-align:left">Content</th>
          <th>👍</th>
          <th>💬</th>
          <th>🔁</th>
          <th>🗨️</th>
          <th>👁️</th>
          <th>Link</th>
        </tr>
      </thead>
      <tbody>${rows}</tbody>
    </table>
  </div>
`;

return [{ json: { hasItems: true, html } }];

const posts = $items('Split Out');

const OUT = items.map((ins, i) => {
  const post = (posts[i] || {}).json || {};

  const arr = ins.json?.data || [];
  const m = Object.fromEntries(arr.map(x => [x.name, x.values?.[0]?.value]));

  const ts = post.timestamp || post.created_time || post.created_at || '';

  return {
    json: {
      id: post.id,
      text: (post.text || '').trim(),
      timestamp: ts,
      permalink: post.permalink,
      likes: m.likes ?? 0,
      replies: m.replies ?? 0,
      reposts: m.reposts ?? 0,
      quotes: m.quotes ?? 0,
      views: m.views ?? m.impressions ?? 0
    }
  };
});

return OUT;
